dashboard.definition:
{
	"title": "Last Event Monitor",
	"description": "",
	"inputs": {
		"input_global_time": {
			"options": {
				"defaultValue": "-24h,now",
				"token": "global_time"
			},
			"title": "Time Range",
			"type": "input.timerange"
		}
	},
	"defaults": {
		"dataSources": {
			"ds.search": {
