	"dataSources": {
		"ds_base_monitored_source_status": {
			"name": "Base - monitored host/index source status",
			"options": {
				"query": "| inputlookup host_index_alert\n| where enabled=1\n| eval in_lookup=1\n\n| append [\n    | tstats latest(_time) as latest_event where index=* earliest=$global_time.earliest$ latest=$global_time.latest$ by host index\n    | eval in_tstats=1\n]\n\n| stats\n    max(in_lookup) as in_lookup\n    max(in_tstats) as in_tstats\n    values(work_time) as work_time\n    values(non_work_time) as non_work_time\n    values(enabled) as enabled\n    values(first_seen) as first_seen\n    values(last_seen_discovery) as last_seen_discovery\n    values(comment) as comment\n    max(latest_event) as latest_event\n    by host index\n\n| where in_lookup=1\n\n| eval work_time=tonumber(mvindex(work_time,0))\n| eval non_work_time=tonumber(mvindex(non_work_time,0))\n\n| eval current_hour=tonumber(strftime(now(), \"%H\"))\n| eval current_wday=tonumber(strftime(now(), \"%w\"))\n| eval is_work_hours=if(current_wday>=1 AND current_wday<=5 AND current_hour>=9 AND current_hour<18,1,0)\n| eval work_window=if(is_work_hours=1,\"Work time\",\"Non-work time\")\n| eval threshold_min=if(is_work_hours=1,work_time,non_work_time)\n\n| eval time_since_last_event_min=if(isnull(latest_event),null(),round((now()-latest_event)/60,0))\n| eval over_threshold_min=if(time_since_last_event_min>threshold_min,time_since_last_event_min-threshold_min,0)\n\n| eval status=case(\n    isnull(latest_event), \"No Data\",\n    time_since_last_event_min<=threshold_min, \"OK\",\n    time_since_last_event_min>threshold_min, \"Late\",\n    true(), \"Unknown\"\n)\n\n| eval Latest_Event=if(isnull(latest_event),\"NO EVENTS\",strftime(latest_event,\"%Y-%m-%d %H:%M:%S\"))\n\n| table host index status time_since_last_event_min over_threshold_min Latest_Event threshold_min work_window work_time non_work_time first_seen last_seen_discovery comment",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"type": "ds.search"
		},
		"ds_chain_full_last_event_table": {
			"name": "Chain - full last event table",
			"options": {
				"extend": "ds_base_monitored_source_status",
				"query": "| table host index status  over_threshold_min Latest_Event threshold_min work_window work_time non_work_time first_seen last_seen_discovery comment\n| sort status -time_since_last_event_min"
			},
			"type": "ds.chain"
		},
		"ds_chain_late": {
			"name": "Chain - KPI Late with percentage",
			"options": {
				"extend": "ds_base_monitored_source_status",
				"query": "| eventstats count as total\n| search status=\"Late\"\n| stats count as value max(total) as total\n| eval percent=if(total>0,round(value*100/total,1),0)\n| eval percent_label=percent.\"% of total\"\n| table value percent_label"
			},
			"type": "ds.chain"
		},
		"ds_chain_no_data": {
			"name": "Chain - KPI No Data with percentage",
			"options": {
				"extend": "ds_base_monitored_source_status",
				"query": "| eventstats count as total\n| search status=\"No Data\"\n| stats count as value max(total) as total\n| eval percent=if(total>0,round(value*100/total,1),0)\n| eval percent_label=percent.\"% of total\"\n| table value percent_label"
			},
			"type": "ds.chain"
		},
		"ds_chain_ok": {
			"name": "Chain - KPI OK with percentage",
			"options": {
				"extend": "ds_base_monitored_source_status",
				"query": "| eventstats count as total\n| search status=\"OK\"\n| stats count as value max(total) as total\n| eval percent=if(total>0,round(value*100/total,1),0)\n| eval percent_label=percent.\"% of total\"\n| table value percent_label"
			},
			"type": "ds.chain"
		},
		"ds_chain_problem_sources": {
			"name": "Chain - problem sources table",
			"options": {
				"extend": "ds_base_monitored_source_status",
				"query": "| eval selected_status=\"$selected_status$\"\r\n| where selected_status=\"All\" OR status=selected_status\r\n| eval status=case(\r\n    status=\"No Data\", \"Critical\",\r\n    status=\"Late\", \"Warning\",\r\n    status=\"OK\", \"OK\",\r\n    true(), status\r\n)\r\n| table host index status over_threshold_min Latest_Event threshold_min work_window comment\r\n| sort status -over_threshold_min"
			},
			"type": "ds.chain"
		},
		"ds_chain_status_by_index": {
			"name": "Chain - status by index chart",
			"options": {
				"extend": "ds_base_monitored_source_status",
				"query": "| chart count over index by status"
			},
			"type": "ds.chain"
		},
		"ds_chain_status_distribution": {
			"name": "Chain - status distribution pie",
			"options": {
				"extend": "ds_base_monitored_source_status",
				"query": "| stats count by status\n| sort - count"
			},
			"type": "ds.chain"
		},
		"ds_chain_total_monitored": {
			"name": "Chain - KPI total monitored with percentage",
			"options": {
				"extend": "ds_base_monitored_source_status",
				"query": "| stats count as value\n| eval percent_label=\"100% of monitored sources\"\n| table value percent_label"
			},
			"type": "ds.chain"
		}
	},
	"layout": {
		"globalInputs": [
			"input_global_time"
		],
		"layoutDefinitions": {
			"layout_1": {
				"options": {
					"backgroundColor": "transparent",
					"display": "fit-to-width",
					"height": 1450,
					"width": 1760
				},
				"structure": [
					{
						"item": "viz_EM1gDYdY",
